try {

const fontBase = { family: "'Georama', sans-serif", size: 11 };
const colorMuted = "#999";
const tooltipBase = {
    backgroundColor: "#fff",
    borderColor: "#ddd",
    borderWidth: 1,
    titleColor: "#111",
    bodyColor: "#555",
    titleFont: { family: "'Georama', sans-serif", size: 12, weight: "600" },
    bodyFont: fontBase,
    padding: 10,
};

// ──────────────────────────────────────────────
// CHART 1: Barras agrupadas — Tendencia x Mención
// ¿Qué combinaciones de mención y tendencia concentran
// la mayor cantidad de proyectos?
// ──────────────────────────────────────────────

const tendenciasOrden = [
    "Salud, Cuidado y Neurodiversidad",
    "Educación, Activismo y Género",
    "Ecología, Materialidad y Futuros",
    "Territorio, Identidad y Memoria",
    "Tecnología, Interacción y Medios",
];

const tendenciasCortas = [
    "Salud y Cuidado",
    "Educación y Género",
    "Ecología y Materialidad",
    "Territorio y Memoria",
    "Tecnología e Interacción",
];

const coloresMencionBase = {
    "Diseño (sin mención)": { normal: "rgba(180,180,180,0.75)", hover: "rgba(120,120,120,0.95)", dim: "rgba(180,180,180,0.18)" },
    "Industrial y Servicios": { normal: "rgba(232,87,26,0.55)", hover: "rgba(200,60,10,0.95)", dim: "rgba(232,87,26,0.12)" },
    "Visual y Medios": { normal: "rgba(232,87,26,0.95)", hover: "rgba(160,30,0,1)", dim: "rgba(232,87,26,0.15)" },
};

function coloresPorEstado(label, hoveredIndex, dataIndex) {
    const c = coloresMencionBase[label];
    if (hoveredIndex === null) return c.normal;
    return hoveredIndex === dataIndex ? c.hover : c.dim;
}

let barraHoverIndex = null;

const chartBarras = new Chart(document.getElementById("barrasMencionTendencia"), {
    type: "bar",
    data: {
        labels: tendenciasCortas,
        datasets: [
            {
                label: "Diseño (sin mención)",
                data: [9, 6, 10, 11, 7],
                backgroundColor: tendenciasCortas.map((_, i) => coloresPorEstado("Diseño (sin mención)", barraHoverIndex, i)),
                borderRadius: 2,
            },
            {
                label: "Industrial y Servicios",
                data: [42, 21, 43, 9, 11],
                backgroundColor: tendenciasCortas.map((_, i) => coloresPorEstado("Industrial y Servicios", barraHoverIndex, i)),
                borderRadius: 2,
            },
            {
                label: "Visual y Medios",
                data: [27, 45, 15, 41, 37],
                backgroundColor: tendenciasCortas.map((_, i) => coloresPorEstado("Visual y Medios", barraHoverIndex, i)),
                borderRadius: 2,
            },
        ],
    },
    options: {
        onHover: (evt, elements) => {
            const nuevoIndex = elements.length ? elements[0].index : null;
            if (nuevoIndex === barraHoverIndex) return;
            barraHoverIndex = nuevoIndex;
            chartBarras.data.datasets.forEach(ds => {
                ds.backgroundColor = tendenciasCortas.map((_, i) => coloresPorEstado(ds.label, barraHoverIndex, i));
            });
            chartBarras.update();
            evt.native.target.style.cursor = nuevoIndex !== null ? "pointer" : "default";
        },
        onClick: (evt, elements) => {
            if (!elements.length) return;
            const tendenciaSeleccionada = tendenciasOrden[elements[0].index];
            buscador.value = tendenciaSeleccionada;
            buscadorNav.value = tendenciaSeleccionada;
            renderTabla(tendenciaSeleccionada);
            document.getElementById("tabla-proyectos").scrollIntoView({ behavior: "smooth", block: "start" });
        },
        scales: {
            x: {
                grid: { display: false },
                border: { color: "#ccc" },
                ticks: { font: fontBase, color: colorMuted },
            },
            y: {
                beginAtZero: true,
                grid: { color: "rgba(0,0,0,0.06)" },
                border: { color: "#bbb", dash: [4, 4] },
                ticks: { font: fontBase, color: colorMuted, stepSize: 10 },
            },
        },
        plugins: {
            legend: {
                display: true,
                position: "top",
                labels: { font: fontBase, color: colorMuted, boxWidth: 12, padding: 14 },
            },
            tooltip: {
                ...tooltipBase,
                callbacks: {
                    label: ctx => `${ctx.dataset.label}: ${ctx.parsed.y} proyectos`,
                    footer: () => "Clic en una barra para filtrar la tabla por esta tendencia",
                },
                footerFont: { family: "'Georama', sans-serif", size: 9, style: "italic" },
                footerColor: "#999",
            },
        },
    },
});


// ──────────────────────────────────────────────
// CHART 2: Líneas — Evolución de tendencias por semestre
// ¿Cómo ha evolucionado el interés por cada tendencia?
// ──────────────────────────────────────────────

const semestresOrden = ["2021-2", "2022-1", "2022-2", "2023-1", "2023-2", "2024-1", "2024-2", "2025-1", "2025-2"];

const evolucionData = {
    "Salud, Cuidado y Neurodiversidad": [0, 1, 2, 3, 11, 5, 21, 15, 20],
    "Educación, Activismo y Género": [0, 5, 2, 5, 13, 15, 13, 2, 17],
    "Ecología, Materialidad y Futuros": [0, 3, 1, 4, 12, 7, 17, 6, 18],
    "Territorio, Identidad y Memoria": [2, 1, 5, 5, 11, 8, 6, 9, 14],
    "Tecnología, Interacción y Medios": [1, 0, 1, 4, 8, 4, 12, 12, 13],
};

const coloresLinea = {
    "Salud, Cuidado y Neurodiversidad": "#e8571a",
    "Educación, Activismo y Género": "#c9491a",
    "Ecología, Materialidad y Futuros": "#a83d1c",
    "Territorio, Identidad y Memoria": "#87331c",
    "Tecnología, Interacción y Medios": "#69291b",
};

let lineaHoverTendencia = null;

function estiloLinea(t, activa) {
    if (activa === null) {
        return {
            borderColor: coloresLinea[t],
            backgroundColor: coloresLinea[t],
            borderWidth: t === "Tecnología, Interacción y Medios" ? 2.5 : 1.5,
        };
    }
    const esActiva = t === activa;
    return {
        borderColor: esActiva ? coloresLinea[t] : "rgba(220,220,220,0.7)",
        backgroundColor: esActiva ? coloresLinea[t] : "rgba(220,220,220,0.7)",
        borderWidth: esActiva ? 3.5 : 1,
    };
}

const chartLineas = new Chart(document.getElementById("lineaEvolucion"), {
    type: "line",
    data: {
        labels: semestresOrden,
        datasets: tendenciasOrden.map(t => ({
            label: t,
            data: evolucionData[t],
            ...estiloLinea(t, null),
            pointRadius: 3,
            pointHoverRadius: 6,
            tension: 0.25,
            fill: false,
        })),
    },
    options: {
        onHover: (evt, elements, chart) => {
            // Detecta sobre qué dataset está el cursor (línea o punto más cercano)
            const puntos = chart.getElementsAtEventForMode(evt, "nearest", { intersect: false, axis: "x" }, false);
            let nuevaTendencia = null;
            if (elements.length) {
                nuevaTendencia = tendenciasOrden[elements[0].datasetIndex];
            }
            if (nuevaTendencia === lineaHoverTendencia) return;
            lineaHoverTendencia = nuevaTendencia;
            chart.data.datasets.forEach((ds, i) => {
                Object.assign(ds, estiloLinea(tendenciasOrden[i], lineaHoverTendencia));
            });
            chart.update();
            evt.native.target.style.cursor = nuevaTendencia !== null ? "pointer" : "default";
        },
        plugins: {
            legend: {
                display: true,
                position: "bottom",
                labels: { font: { family: "'Georama', sans-serif", size: 10 }, color: colorMuted, boxWidth: 10, padding: 10 },
                onHover: (evt, item, legend) => {
                    const t = tendenciasOrden[item.index];
                    if (t === lineaHoverTendencia) return;
                    lineaHoverTendencia = t;
                    legend.chart.data.datasets.forEach((ds, i) => {
                        Object.assign(ds, estiloLinea(tendenciasOrden[i], lineaHoverTendencia));
                    });
                    legend.chart.update();
                },
                onLeave: (evt, item, legend) => {
                    lineaHoverTendencia = null;
                    legend.chart.data.datasets.forEach((ds, i) => {
                        Object.assign(ds, estiloLinea(tendenciasOrden[i], null));
                    });
                    legend.chart.update();
                },
            },
            tooltip: {
                ...tooltipBase,
                callbacks: {
                    label: ctx => `${ctx.dataset.label}: ${ctx.parsed.y}`,
                },
            },
        },
        scales: {
            x: {
                grid: { display: false },
                border: { color: "#ccc" },
                ticks: { font: fontBase, color: colorMuted },
            },
            y: {
                beginAtZero: true,
                grid: { color: "rgba(0,0,0,0.06)" },
                border: { color: "#bbb", dash: [4, 4] },
                ticks: { font: fontBase, color: colorMuted, stepSize: 5 },
                title: {
                    display: true,
                    text: "Proyectos aprobados",
                    font: fontBase,
                    color: colorMuted,
                },
            },
        },
    },
});

document.getElementById("lineaEvolucion").addEventListener("mouseleave", () => {
    if (lineaHoverTendencia === null) return;
    lineaHoverTendencia = null;
    chartLineas.data.datasets.forEach((ds, i) => {
        Object.assign(ds, estiloLinea(tendenciasOrden[i], null));
    });
    chartLineas.update();
});

} catch (err) {
    console.error("No se pudieron inicializar los gráficos Chart.js:", err);
}

// ──────────────────────────────────────────────
// TABLA DINÁMICA CON BUSCADOR
// ──────────────────────────────────────────────

const tbody = document.getElementById("tabla-body");
const buscador = document.getElementById("buscador");
const buscadorNav = document.getElementById("buscador-nav");
const sinResultados = document.getElementById("sin-resultados");

function renderTabla(filtro) {
    const termino = filtro.toLowerCase().trim();
    const filtrados = proyectos.filter(p => {
        const texto = `${p.a} ${p.t} ${p.tn} ${p.g} ${p.pr} ${p.r} ${p.sem}`.toLowerCase();
        return texto.includes(termino);
    });

    tbody.innerHTML = "";

    if (filtrados.length === 0) {
        sinResultados.hidden = false;
        return;
    }

    sinResultados.hidden = true;

    const frag = document.createDocumentFragment();
    filtrados.forEach(p => {
        const tr = document.createElement("tr");
        const proyectoCelda = p.repo
            ? `<a href="${p.repo}" target="_blank" rel="noopener">${p.pr}</a>`
            : `${p.pr} <span class="sin-repo" title="Proyecto sin ficha disponible en el repositorio">(sin repositorio)</span>`;
        tr.innerHTML = `
            <td>${p.sem}</td>
            <td>${p.a}</td>
            <td>${proyectoCelda}</td>
            <td>${p.tn}</td>
            <td>${p.g}</td>
            <td>${p.n !== null ? p.n.toFixed(1) : "—"}</td>
        `;
        frag.appendChild(tr);
    });
    tbody.appendChild(frag);
}

buscador.addEventListener("input", e => {
    renderTabla(e.target.value);
    if (buscadorNav.value !== e.target.value) buscadorNav.value = e.target.value;
});

buscadorNav.addEventListener("input", e => {
    renderTabla(e.target.value);
    if (buscador.value !== e.target.value) buscador.value = e.target.value;
});

// Render inicial
renderTabla("");
